export function stdUiBoardgameBoard(params: StdUiBoardgameBoardParams = {}): OrbitalDefinition[] {
  return [
    stdUiBoardgameBoardBoardgameBoardOrbital(params.BoardgameBoard ?? {}),
  ];
}
